import { createSlice, PayloadAction } from '@reduxjs/toolkit';

interface UserState {
  firstName: string;
  dob: any;
  mobile: string;
  sex: string;
  id: any;
  idType: any;
}

const initialState: UserState = {
  userData: {
    firstName: '',
    dob: '',
    mobile: '',
    sex: '',
    id: '',
    idType: '',
  },
};

